 13→
 14→const stripeKey = process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY ?? "";
 15→const stripePromise = stripeKey ? loadStripe(stripeKey) : null;
 16→
 17→function UpdateCardInner({
 18→  onConfirm,
 19→  submitting,
 20→}: {
 21→  onConfirm: (setupIntentId: string) => Promise<void>;
 22→  submitting: boolean;
 23→}) {
 24→  const stripe = useStripe();
 25→  const elements = useElements();
 26→  const [error, setError] = useState<string | null>(null);
 27→
 28→  async function confirm() {
 29→    if (!stripe || !elements) return;
 30→    setError(null);
 31→    const res = await stripe.confirmSetup({
 32→      elements,
 33→      redirect: "if_required",
 34→    });
 35→    if (res.error) {
 36→      setError(res.error.message ?? "Could not save card.");
 37→      return;
 38→    }
 39→    const id = res.setupIntent?.id ?? "";
 40→    const status = res.setupIntent?.status ?? "";
 41→    if (!id || status !== "succeeded") {
 42→      setError("Card was not saved. Please try again.");
 43→      return;
 44→    }
 45→    await onConfirm(id);
 46→  }
 47→
 48→  return (
 49→    <div className="grid gap-3">
 50→      {error ? <ErrorAlert error={error} /> : null}
 51→      <div className="rounded-xl bg-white/60 p-4 ring-1 ring-[color:var(--lr-border)]">
 52→        <PaymentElement />
 53→      </div>
 54→      <button
 55→        type="button"
 56→        className="lr-btn lr-btn-primary inline-flex w-full items-center justify-center px-4 py-2 text-sm font-semibold disabled:opacity-50"
 57→        disabled={submitting || !stripe || !elements}
 58→        onClick={confirm}
 59→      >
 60→        {submitting ? "Saving…" : "Save card"}
 61→      </button>
 62→      <div className="text-xs text-[color:var(--lr-muted)]">
 63→        Your card will be used to authorize upcoming pickups within 7 days of the pickup.
 64→      </div>
 65→    </div>
 66→  );
 67→}
