 69→function UpdateCard({
 70→  clientSecret,
 71→  submitting,
 72→  onConfirm,
 73→}: {
 74→  clientSecret: string;
 75→  submitting: boolean;
 76→  onConfirm: (setupIntentId: string) => Promise<void>;
 77→}) {
