 96→const CANCEL_REASONS = [
 97→  "Too expensive",
 98→  "Too much food",
 99→  "Moving / can\u2019t pick up",
100→  "Quality issues",
101→  "Other",
102→] as const;
103→
104→function CancelFlow({
105→  open,
106→  submitting,
107→  onPause,
108→  onCancel,
109→  onClose,
110→}: {
111→  open: boolean;
112→  submitting: boolean;
113→  onPause: () => void;
114→  onCancel: () => void;
115→  onClose: () => void;
116→}) {
117→  const ref = useRef<HTMLDialogElement>(null);
118→  const [step, setStep] = useState<1 | 2>(1);
119→  const [reason, setReason] = useState<string>(CANCEL_REASONS[0]);
120→  const [prevOpen, setPrevOpen] = useState(false);
121→
122→  // Reset to step 1 whenever the dialog opens (React-recommended prop→state pattern)
123→  if (open && !prevOpen) {
124→    setPrevOpen(true);
125→    setStep(1);
126→    setReason(CANCEL_REASONS[0]);
127→  } else if (!open && prevOpen) {
128→    setPrevOpen(false);
129→  }
130→
131→  useEffect(() => {
132→    const el = ref.current;
133→    if (!el) return;
134→    if (open && !el.open) el.showModal();
135→    if (!open && el.open) el.close();
136→  }, [open]);
137→
138→  const handleDialogCancel = useCallback(
139→    (e: React.SyntheticEvent) => {
140→      e.preventDefault();
141→      onClose();
142→    },
143→    [onClose],
144→  );
145→
146→  if (!open) return null;
147→
148→  return (
149→    <dialog
150→      ref={ref}
151→      onCancel={handleDialogCancel}
152→      className="fixed inset-0 z-50 m-auto max-w-sm rounded-2xl border-0 bg-white p-6 shadow-xl backdrop:bg-black/30"
153→    >
154→      {step === 1 ? (
155→        <>
156→          <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
157→            Before you go&hellip;
158→          </h2>
159→          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">
160→            Would you like to pause your subscription instead? You can resume
161→            anytime from your dashboard.
162→          </p>
163→          <div className="mt-5 grid gap-3">
164→            <button
165→              type="button"
166→              className="lr-btn lr-btn-primary w-full px-4 py-2 text-sm font-semibold disabled:opacity-50"
167→              disabled={submitting}
168→              onClick={onPause}
169→            >
170→              {submitting ? "Pausing\u2026" : "Pause subscription"}
171→            </button>
172→            <button
173→              type="button"
174→              className="text-sm text-[color:var(--lr-muted)] underline"
175→              onClick={() => setStep(2)}
176→            >
177→              No, cancel my subscription
178→            </button>
179→          </div>
180→        </>
181→      ) : (
182→        <>
183→          <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
184→            We&rsquo;re sorry to see you go
185→          </h2>
186→          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">
187→            Help us improve &mdash; why are you canceling?
188→          </p>
189→          <fieldset className="mt-4 grid gap-2">
190→            {CANCEL_REASONS.map((r) => (
191→              <label
192→                key={r}
193→                className="flex items-center gap-2 text-sm text-[color:var(--lr-ink)]"
194→              >
195→                <input
196→                  type="radio"
197→                  name="cancel-reason"
198→                  value={r}
199→                  checked={reason === r}
200→                  onChange={() => setReason(r)}
201→                  className="accent-[color:var(--lr-primary)]"
202→                />
203→                {r}
204→              </label>
205→            ))}
206→          </fieldset>
207→          <div className="mt-5 grid gap-3">
208→            <button
209→              type="button"
210→              className="w-full rounded-full bg-rose-600 px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-rose-700 disabled:opacity-50"
211→              disabled={submitting}
212→              onClick={() => {
213→                console.log("[CancelFlow] reason:", reason);
214→                onCancel();
215→              }}
216→            >
217→              {submitting ? "Canceling\u2026" : "Cancel subscription"}
218→            </button>
219→            <button
220→              type="button"
221→              className="text-sm text-[color:var(--lr-muted)] underline"
222→              onClick={() => setStep(1)}
223→            >
224→              Go back
225→            </button>
226→          </div>
227→        </>
228→      )}
229→    </dialog>
230→  );
231→}
